def main():
    import argparse
    parser = argparse.ArgumentParser(description="Merge D1 baseline with D2-D5 LLM evaluations")
    parser.add_argument("--output", type=str,
                        default=str(BASELINE_DIR / "d1d5-claude-opus-baseline.json"),
                        help="Output file for merged results")
    parser.add_argument("--report", type=str,
                        default=str(BASELINE_DIR / "d1d5-claude-opus-report.md"),
                        help="Output file for human-readable report")
    args = parser.parse_args()

    # Run D1 checks
    skill_paths = discover_skills(SKILLS_DIR)
    print(f"Evaluating {len(skill_paths)} skills (D1 deterministic + D2-D5 LLM)...", file=sys.stderr)

    results = []
    for skill_path in skill_paths:
        skill_name = skill_path.parent.name
        parsed = parse_skill(skill_path)
        d1 = check_d1_structural(parsed)

        # Get D2-D5 from LLM evaluations
        llm_dims = D2D5_EVALUATIONS.get(skill_name, {})

        if llm_dims:
            verdict = compute_overall_verdict(d1, llm_dims)
        else:
            # Skills without D2-D5 evaluations: D1-only verdict
            verdict = "PASS" if d1["label"] == "COMPLIANT" else ("IMPROVE" if d1["label"] == "PARTIAL" else "REWRITE")

        result = {
            "skill_name": skill_name,
            "skill_path": str(skill_path),
            "dimensions": {
                "D1_structural": d1,
                **llm_dims,
            },
            "overall_verdict": verdict,
            "priority_fixes": collect_priority_fixes(d1, llm_dims),
        }
        results.append(result)

    # Save JSON
    Path(args.output).write_text(
        json.dumps(results, indent=2, ensure_ascii=False), encoding="utf-8"
    )
    print(f"Results saved to {args.output}", file=sys.stderr)

    # Save report
    report = generate_report(results)
    Path(args.report).write_text(report, encoding="utf-8")
    print(f"Report saved to {args.report}", file=sys.stderr)

    # Summary
    verdicts = {}
    for r in results:
        v = r["overall_verdict"]
        verdicts[v] = verdicts.get(v, 0) + 1

    print(f"\n=== D1+D2-D5 SWEEP RESULTS ===")
    for v in ["PASS", "IMPROVE", "REWRITE"]:
        count = verdicts.get(v, 0)
        emoji = {"PASS": "✅", "IMPROVE": "⚠️", "REWRITE": "🔴"}[v]
        print(f"  {emoji} {v}: {count}")

    # Print per-skill
    for r in results:
        emoji = {"PASS": "✅", "IMPROVE": "⚠️", "REWRITE": "🔴"}.get(r["overall_verdict"], "❓")
        dims = r["dimensions"]
        d2 = dims.get("D2_clarity", {}).get("label", "—")
        d3 = dims.get("D3_alignment", {}).get("label", "—")
        d4 = dims.get("D4_fitness", {}).get("label", "—")
        d5 = dims.get("D5_economy", {}).get("label", "—")
        print(f"  {emoji} {r['skill_name']}: D1={dims['D1_structural']['label']} D2={d2} D3={d3} D4={d4} D5={d5} → {r['overall_verdict']}")


if __name__ == "__main__":
    main()
